const raw = $input.first().json;
function asObject(v) {
  if (v == null) return null;
  if (typeof v === 'object' && !Array.isArray(v)) return v;
  if (typeof v === 'string') {
    const t = v.trim();
    if (!t) return null;
    try { return JSON.parse(t); } catch (e) {
      throw new Error('Body no es JSON válido: ' + e.message);
    }
  }
  return null;
}
const nested = asObject(raw.body) ?? {};
const need = ['session_id', 'patient_id', 'audio_uri'];
const b = {};
for (const k of need) {
  const v = nested[k] ?? raw[k];
  if (v !== undefined && v !== null && v !== '') b[k] = v;
}
for (const k of need) {
  if (!b[k]) {
    throw new Error(
      'Falta ' + k + ': el Webhook recibió body vacío o no parseado. ' +
      'Causa habitual: Content-Type distinto de application/json (p. ej. charset en el cliente).'
    );
  }
}
const clinical =
  nested.clinical && typeof nested.clinical === 'object'
    ? nested.clinical
    : raw.clinical && typeof raw.clinical === 'object'
      ? raw.clinical
      : {};
const physician = nested.physician_id ?? raw.physician_id;
return [{
  json: {
    session_id: String(b.session_id),
    patient_id: String(b.patient_id),
    physician_id: physician ? String(physician) : null,
    audio_uri: String(b.audio_uri),
    clinical,
    meta: { received_at: new Date().toISOString() },
  },
}];

