const root = $('Code — Validar payload').first().json;
const items = $input.all();
let acoustic = {};
let nlp = {};
for (const it of items) {
  const j = it.json;
  if (j.f0_mean != null || j.jitter != null || j.opensmile) acoustic = j;
  if (j.transcript != null || j.ttr != null || j.whisper) nlp = j;
}
if (!acoustic || Object.keys(acoustic).length === 0) acoustic = items[0]?.json ?? {};
if (!nlp || Object.keys(nlp).length === 0) nlp = items[1]?.json ?? {};
return [{
  json: {
    session_id: root.session_id,
    patient_id: root.patient_id,
    clinical: root.clinical,
    acoustic,
    nlp
  }
}];

// Tomar datos del modelo probabilístico (Postgres no propaga campos al hacer INSERT/UPDATE)
const modelOut = $('HTTP — Modelo probabilístico').first().json;
const root = $('Code — Validar payload').first().json;
const p = { ...modelOut, session_id: modelOut.session_id ?? root.session_id, patient_id: modelOut.patient_id ?? root.patient_id };

const f0 = p.acoustic?.f0_mean ?? p.f0_mean ?? 0;
const jit = (p.acoustic?.jitter ?? p.jitter ?? 0) * 100;
const shim = (p.acoustic?.shimmer ?? p.shimmer ?? 0) * 100;
const ttr = p.nlp?.ttr ?? p.ttr ?? 0;
const wpm = p.nlp?.words_per_min ?? p.words_per_min ?? 0;
const chartAcoustic = {
  type: 'bar',
  data: {
    labels: ['F0 (Hz)', 'Jitter %', 'Shimmer %'],
    datasets: [{
      label: 'Acústico',
      data: [Math.round(f0 * 10) / 10, Math.round(jit * 100) / 100, Math.round(shim * 100) / 100],
      backgroundColor: ['#3b82f6', '#ef4444', '#f59e0b']
    }]
  },
  options: { plugins: { title: { display: true, text: 'Resumen Acústico' } } }
};
const chartLing = {
  type: 'bar',
  data: {
    labels: ['TTR (diversidad)', 'Palabras/min'],
    datasets: [{
      label: 'Lingüístico',
      data: [Math.round(ttr * 1000) / 1000, Math.round(wpm * 10) / 10],
      backgroundColor: ['#8b5cf6', '#10b981']
    }]
  },
  options: { plugins: { title: { display: true, text: 'Métricas NLP' } } }
};
const prob = (p.p_parkinson ?? p.probability ?? 0);
const pct = Math.round(prob * 1000) / 10;
const chartRisk = {
  type: 'doughnut',
  data: {
    labels: ['Riesgo Parkinson', 'Resto'],
    datasets: [{
      data: [pct, Math.max(0, 100 - pct)],
      backgroundColor: [pct >= 70 ? '#ef4444' : pct >= 50 ? '#f59e0b' : '#10b981', '#e5e7eb']
    }]
  },
  options: { plugins: { title: { display: true, text: `Probabilidad estimada: ${pct}%` } } }
};
const enc = (c) => encodeURIComponent(JSON.stringify(c));
return [{
  json: {
    ...p,
    charts: {
      acoustic_png: `https://quickchart.io/chart?c=${enc(chartAcoustic)}&w=500&h=300&format=png`,
      linguistic_png: `https://quickchart.io/chart?c=${enc(chartLing)}&w=500&h=300&format=png`,
      risk_png: `https://quickchart.io/chart?c=${enc(chartRisk)}&w=400&h=400&format=png`
    }
  }
}];

function fastApiDetail(text) {
  if (text == null || typeof text !== 'string') return null;
  const i = text.indexOf('{');
  if (i === -1) return null;
  try {
    const o = JSON.parse(text.slice(i));
    if (o && o.detail != null) {
      return typeof o.detail === 'string' ? o.detail : JSON.stringify(o.detail);
    }
  } catch (err) { /* ignore */ }
  return null;
}

function isMisleadingSuccessPayload(text) {
  if (text == null || typeof text !== 'string') return false;
  const i = text.indexOf('{');
  if (i === -1) return false;
  try {
    const o = JSON.parse(text.slice(i));
    if (o.opensmile === true && o.features) return true;
    if (o.whisper === true && (o.transcript != null || o.metrics)) return true;
    if (typeof o.p_parkinson === 'number') return true;
    if (o.valid === true && o.duration_sec != null) return true;
  } catch (e) { /* ignore */ }
  return false;
}

function pickFromNodeApiError(err) {
  if (!err || typeof err !== 'object') return null;
  const msg = err.message ?? err.description ?? err.reason;
  if (!msg) return null;
  return {
    message: String(msg),
    httpStatus: err.statusCode ?? err.httpStatus ?? err.status ?? null,
    name: err.name ?? err.type ?? null,
  };
}

function pickAxiosLike(item) {
  if (!item || typeof item !== 'object') return null;
  const e = item.error;
  if (e && typeof e === 'object') {
    const msg = e.message ?? e.description ?? e.reason;
    if (msg) {
      return {
        message: String(msg),
        httpStatus: e.statusCode ?? e.status ?? null,
        name: e.name ?? null,
      };
    }
  }
  if (item.name === 'AxiosError' || item.code === 'ERR_BAD_RESPONSE') {
    const msg = item.message;
    if (msg) {
      return {
        message: String(msg),
        httpStatus: item.statusCode ?? item.status ?? null,
        name: item.name ?? null,
      };
    }
  }
  return null;
}

function probeWorkflowErrors() {
  const names = [
    'HTTP — Validar calidad audio',
    'HTTP — Análisis acústico (Praat)',
    'HTTP — Whisper + NLP',
    'HTTP — Modelo probabilístico',
    'Postgres — Registrar sesión',
    'Postgres — Guardar predicción',
  ];
  for (const name of names) {
    try {
      const ref = $(name);
      if (!ref || typeof ref.all !== 'function') continue;
      const list = typeof ref.all === 'function' ? ref.all() : [];
      const also = [];
      if (typeof ref.first === 'function') try { also.push(ref.first()); } catch (e2) { /* ignore */ }
      if (typeof ref.last === 'function') try { also.push(ref.last()); } catch (e3) { /* ignore */ }
      for (const it of [...list, ...also]) {
        if (!it) continue;
        const p = pickFromNodeApiError(it.error);
        if (p) return p;
        if (it.json) {
          const p2 = pickAxiosLike(it.json);
          if (p2) return p2;
        }
      }
    } catch (e) {
      continue;
    }
  }
  return null;
}

const root = $('Code — Validar payload').first().json;
const first = $input.first();
const hasExecShape = first && typeof first === 'object' && ('json' in first || 'error' in first);
const item = hasExecShape
  ? (first.json !== undefined && first.json !== null ? first.json : {})
  : (first || {});
const outerErr = hasExecShape ? first.error : undefined;
let picked = pickFromNodeApiError(outerErr);
if (!picked && typeof $input.all === 'function') {
  for (const it of $input.all()) {
    const ex = it && typeof it === 'object' && ('json' in it || 'error' in it);
    const p = pickFromNodeApiError(ex ? it.error : undefined);
    if (p) {
      picked = p;
      break;
    }
  }
}
if (!picked) picked = probeWorkflowErrors();
if (!picked) picked = pickAxiosLike(item);
if (!picked && item.json && typeof item.json === 'object') {
  picked = pickAxiosLike({ ...item, ...item.json });
}
let message = picked ? picked.message : null;
let httpStatus = picked ? picked.httpStatus : null;
let name = picked ? picked.name : null;

if (message == null && typeof item.message === 'string' && (item.name || item.stack)) {
  message = item.message;
  httpStatus = httpStatus ?? item.statusCode ?? null;
  name = name ?? item.name ?? null;
}

if (message == null) {
  const slim = { ...item };
  delete slim.success;
  delete slim.pairedItem;
  delete slim.item;
  const keys = Object.keys(slim).filter((k) => slim[k] !== undefined);
  if (keys.length === 0) {
    message = 'No se pudo leer el error del nodo (Code no recibe item.error en $input). Keys en json recibido: ' + JSON.stringify(Object.keys(item));
  } else {
    message = JSON.stringify(slim);
  }
}

const detail = fastApiDetail(message);
if (detail) {
  message = detail;
}

if (isMisleadingSuccessPayload(message)) {
  message =
    'Fallo en un paso posterior (Merge, Whisper, predict o Postgres). En n8n abra la ejecución y el nodo en rojo; el texto largo anterior era una respuesta HTTP OK mal interpretada como error.';
}

return [{
  json: {
    session_id: root.session_id,
    patient_id: root.patient_id,
    error: { message, httpStatus, name },
  },
}];
